CREATE TABLE IF NOT EXISTS privacy_discovery_scans (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,case_id uuid NOT NULL,status text NOT NULL DEFAULT 'queued',subject_id text NOT NULL DEFAULT '',sources jsonb NOT NULL DEFAULT '[]',started_at timestamptz,completed_at timestamptz,records_found integer NOT NULL DEFAULT 0,failure_reason text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS privacy_discovered_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,scan_id uuid NOT NULL REFERENCES privacy_discovery_scans(id) ON DELETE CASCADE,source text NOT NULL,record_type text NOT NULL,record_id text NOT NULL DEFAULT '',fields jsonb NOT NULL DEFAULT '{}',redactions jsonb NOT NULL DEFAULT '[]',included boolean NOT NULL DEFAULT true,metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS privacy_fulfillment_packages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,case_id uuid NOT NULL,status text NOT NULL DEFAULT 'draft',format text NOT NULL DEFAULT 'json',record_ids jsonb NOT NULL DEFAULT '[]',checksum text NOT NULL DEFAULT '',approved_by text NOT NULL DEFAULT '',approved_at timestamptz,delivered_at timestamptz,delivery_channel text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_privacy_scans_tenant_status ON privacy_discovery_scans(tenant_id,status,created_at DESC);
CREATE INDEX IF NOT EXISTS idx_privacy_packages_tenant_status ON privacy_fulfillment_packages(tenant_id,status,created_at DESC);
